import React, { useEffect, useState } from 'react';
import API from '../api/axios';

const STAGES = ['negotiation', 'agreement', 'closed'];
const STAGE_COLORS = { negotiation: '#f59e0b', agreement: '#3b82f6', closed: '#10b981' };
const STAGE_ICONS = { negotiation: '🔄', agreement: '📝', closed: '✅' };

export default function Deals() {
  const [deals, setDeals] = useState([]);
  const [clients, setClients] = useState([]);
  const [properties, setProperties] = useState([]);
  const [agents, setAgents] = useState([]);
  const [showForm, setShowForm] = useState(false);
  const [stats, setStats] = useState({});
  const [form, setForm] = useState({ client_id: '', property_id: '', agent_id: '', deal_value: '' });

  const fetchAll = async () => {
    const [dealsRes, clientsRes, propsRes, statsRes] = await Promise.all([
      API.get('/deals'),
      API.get('/clients'),
      API.get('/properties'),
      API.get('/deals/stats/summary'),
    ]);
    setDeals(dealsRes.data);
    setClients(clientsRes.data);
    setProperties(propsRes.data);
    setStats(statsRes.data);
  };

  useEffect(() => { fetchAll(); }, []);

  const handleSubmit = async (e) => {
    e.preventDefault();
    await API.post('/deals', form);
    setShowForm(false);
    setForm({ client_id: '', property_id: '', agent_id: '', deal_value: '' });
    fetchAll();
  };

  const moveStage = async (dealId, newStage) => {
    await API.put(`/deals/${dealId}/stage`, { stage: newStage });
    fetchAll();
  };

  const deleteDeal = async (id) => {
    if (window.confirm('Delete this deal?')) {
      await API.delete(`/deals/${id}`);
      fetchAll();
    }
  };

  return (
    <div style={styles.page}>
      <div style={styles.header}>
        <h1 style={styles.title}>🤝 Deal Pipeline</h1>
        <button onClick={() => setShowForm(!showForm)} style={styles.addBtn}>+ New Deal</button>
      </div>

      {/* Stats Row */}
      <div style={styles.statsRow}>
        {[
          { label: 'Total Deals', value: stats.total_deals || 0, icon: '📊', color: '#3b82f6' },
          { label: 'Deals Closed', value: stats.closed_deals || 0, icon: '✅', color: '#10b981' },
          { label: 'Total Revenue', value: `₹${Number(stats.total_revenue || 0).toLocaleString()}`, icon: '💰', color: '#8b5cf6' },
          { label: 'Commission Earned', value: `₹${Number(stats.total_commission || 0).toLocaleString()}`, icon: '🏆', color: '#f59e0b' },
        ].map(s => (
          <div key={s.label} style={{ ...styles.statCard, borderTop: `3px solid ${s.color}` }}>
            <span style={{ fontSize: 22 }}>{s.icon}</span>
            <div style={{ ...styles.statValue, color: s.color }}>{s.value}</div>
            <div style={styles.statLabel}>{s.label}</div>
          </div>
        ))}
      </div>

      {/* Add Deal Form */}
      {showForm && (
        <div style={styles.formBox}>
          <h3 style={{ marginBottom: 16 }}>New Deal</h3>
          <form onSubmit={handleSubmit} style={styles.formGrid}>
            <select required style={styles.input} value={form.client_id} onChange={e => setForm({ ...form, client_id: e.target.value })}>
              <option value="">Select Client *</option>
              {clients.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
            </select>
            <select required style={styles.input} value={form.property_id} onChange={e => setForm({ ...form, property_id: e.target.value })}>
              <option value="">Select Property *</option>
              {properties.filter(p => p.status === 'available').map(p => (
                <option key={p.id} value={p.id}>{p.title} — ₹{Number(p.price).toLocaleString()}</option>
              ))}
            </select>
            <input placeholder="Deal Value (₹) *" required type="number" style={styles.input}
              value={form.deal_value} onChange={e => setForm({ ...form, deal_value: e.target.value })} />
            <div style={{ gridColumn: '1/-1', display: 'flex', gap: 10 }}>
              <button type="submit" style={styles.addBtn}>Create Deal</button>
              <button type="button" onClick={() => setShowForm(false)} style={styles.cancelBtn}>Cancel</button>
            </div>
          </form>
        </div>
      )}

      {/* Kanban Board */}
      <div style={styles.kanban}>
        {STAGES.map(stage => {
          const stagDeals = deals.filter(d => d.stage === stage);
          return (
            <div key={stage} style={styles.column}>
              <div style={{ ...styles.columnHeader, borderTop: `3px solid ${STAGE_COLORS[stage]}` }}>
                <span>{STAGE_ICONS[stage]} {stage.charAt(0).toUpperCase() + stage.slice(1)}</span>
                <span style={{ ...styles.countBadge, background: STAGE_COLORS[stage] }}>{stagDeals.length}</span>
              </div>
              <div style={styles.columnBody}>
                {stagDeals.length === 0 && <div style={styles.emptyCol}>No deals here</div>}
                {stagDeals.map(deal => (
                  <div key={deal.id} style={styles.dealCard}>
                    <div style={styles.dealTitle}>{deal.property_title || 'Property'}</div>
                    <div style={styles.dealMeta}>👤 {deal.client_name || '—'}</div>
                    <div style={styles.dealMeta}>🧑‍💼 {deal.agent_name || '—'}</div>
                    <div style={{ ...styles.dealValue, color: STAGE_COLORS[stage] }}>
                      ₹{Number(deal.deal_value || 0).toLocaleString()}
                    </div>
                    <div style={styles.dealMeta}>Commission: ₹{Number(deal.commission_amount || 0).toLocaleString()}</div>
                    <div style={styles.dealActions}>
                      {stage !== 'negotiation' && (
                        <button onClick={() => moveStage(deal.id, STAGES[STAGES.indexOf(stage) - 1])}
                          style={styles.moveBtn}>← Back</button>
                      )}
                      {stage !== 'closed' && (
                        <button onClick={() => moveStage(deal.id, STAGES[STAGES.indexOf(stage) + 1])}
                          style={{ ...styles.moveBtn, background: STAGE_COLORS[STAGES[STAGES.indexOf(stage) + 1]], color: '#fff' }}>
                          Next →
                        </button>
                      )}
                      <button onClick={() => deleteDeal(deal.id)} style={styles.delBtn}>🗑️</button>
                    </div>
                  </div>
                ))}
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
}

const styles = {
  page: { padding: 24 },
  header: { display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 20 },
  title: { fontSize: 22, fontWeight: 700, color: '#1e293b' },
